/* eslint-disable react/prop-types */
import { styled } from 'styled-components';

import { BUTTON_AS_BUTTON } from '#components/Button/Button.constants';
import IconButton from '#components/IconButton';

type ShowHideToggleProps = {
  isShowing: boolean;
};

import EyeHiddenSVG from '#assets/icons/eye-hidden-24.svg';
import EyeVisibleSVG from '#assets/icons/eye-visible-24.svg';

export const ShowButton = styled(IconButton).attrs({
  svg: EyeVisibleSVG,
  isCosy: false,
  forwardedAs: BUTTON_AS_BUTTON,
})`
  width: 42px;
  height: 42px;
  cursor: pointer;
`;

export const HideButton = styled(IconButton).attrs({
  svg: EyeHiddenSVG,
  isCosy: false,
  forwardedAs: BUTTON_AS_BUTTON,
})`
  width: 42px;
  height: 42px;
  cursor: pointer;
`;

const ShowHideToggle: React.FC<ShowHideToggleProps> = ({
  isShowing,
  ...props
}) => {
  return isShowing ? (
    <HideButton svg={EyeVisibleSVG} {...props} />
  ) : (
    <ShowButton svg={EyeHiddenSVG} {...props} />
  );
};

export default ShowHideToggle;
